insert into public.codes (code, target_type, target_id, active) select upper(c.payload->'data'->>'qrCode'), 'challenge', ch.id, true from public.challenges ch join lateral (select ch.payload) c on true where ch.slug like 'ch-%' and ch.type = 'panna_qr' and c.payload->'data'->>'qrCode' is not null on conflict (code) do update set target_type = excluded.target_type, target_id = excluded.target_id, active = true;